package governance

import (
	"bytes"
	"context"
	"errors"
	"fmt"
	"os/exec"
	"strings"
)

// gitGrepNoMatch is the exit code git grep uses when no lines match. It is
// distinct from real failure exits (128 for invalid revision, 2 for syntax
// errors) so the verifier can accept "no generated artifacts" without
// masking actual breakage.
const gitGrepNoMatch = 1

// GoGeneratedPrefix is the canonical "// Code generated by gocell generate "
// prefix that gocell-generated Go files start with. The exact phrasing is
// the boundary contract enforced by writeGeneratedFile (cmd/gocell/app
// generate.go) on the producer side and by generatedverify reverse
// enumeration on the verifier side; both must read this constant rather
// than re-spelling the literal.
const GoGeneratedPrefix = "// Code generated by gocell generate "

// YAMLGeneratedPrefix is the YAML-comment counterpart used for boundary.yaml,
// metrics-schema.yaml, and any future generated YAML artifact.
const YAMLGeneratedPrefix = "# Generated by gocell generate "

// IsGoCellGenerated reports whether content carries either of the gocell
// generator header sentinels. Callers pass the leading bytes of a candidate
// file.
func IsGoCellGenerated(content []byte) bool {
	return bytes.HasPrefix(content, []byte(GoGeneratedPrefix)) ||
		bytes.HasPrefix(content, []byte(YAMLGeneratedPrefix))
}

// ListGeneratedInHEAD returns repo-relative paths of every committed file at
// root whose first line carries a gocell generator header sentinel. Result
// is filtered to the file extensions generators currently emit (.go, .yml,
// .yaml); any future generator producing a different extension must extend
// this filter alongside the generator change so reverse enumeration stays
// closed.
//
// Implementation uses `git grep` so the entire HEAD tree is scanned in a
// single subprocess; per-file probing through `git show` would not scale
// for large work trees.
//
// An empty repository (HEAD does not yet resolve) or "no matches" returns
// (nil, nil) without error.
func ListGeneratedInHEAD(ctx context.Context, root string) ([]string, error) {
	has, err := hasHEAD(ctx, root)
	if err != nil {
		return nil, err
	}
	if !has {
		return nil, nil
	}
	// Both prefixes contain no ERE metacharacters, so simple alternation is
	// safe. The leading "^" anchors the match to the start of a line, and
	// generated files emit the sentinel as the first line.
	pattern := "^(" + GoGeneratedPrefix + "|" + YAMLGeneratedPrefix + ")"
	out, err := runGit(ctx, "-C", root, "grep",
		"-I",
		"-l",
		"-E",
		pattern,
		"HEAD",
		"--",
		"*.go", "*.yml", "*.yaml",
	)
	if err != nil {
		return interpretGitGrepError(ctx, err, out)
	}
	return parseGeneratedPaths(out), nil
}

// interpretGitGrepError translates a git-grep failure into the right
// (paths, err) tuple: ctx cancellation propagates, a "no match" exit is
// the empty result, and any other ExitError carries stderr forward.
func interpretGitGrepError(ctx context.Context, gitErr error, out []byte) ([]string, error) {
	if cerr := ctx.Err(); cerr != nil {
		return nil, cerr
	}
	var exitErr *exec.ExitError
	if errors.As(gitErr, &exitErr) {
		if exitErr.ExitCode() == gitGrepNoMatch {
			return nil, nil
		}
		return nil, fmt.Errorf("git grep HEAD: %s", strings.TrimSpace(string(out)))
	}
	return nil, fmt.Errorf("git grep HEAD: %w", gitErr)
}

// parseGeneratedPaths extracts repo-relative paths from `git grep <tree>`
// output ("<tree>:<path>" per line) and skips testdata/ subtrees so
// archtest fixtures bearing the generator sentinel do not appear as
// reverse-enumeration drift.
func parseGeneratedPaths(out []byte) []string {
	trimmed := bytes.TrimSpace(out)
	if len(trimmed) == 0 {
		return nil
	}
	lines := bytes.Split(trimmed, []byte("\n"))
	paths := make([]string, 0, len(lines))
	for _, line := range lines {
		s := strings.TrimSpace(string(line))
		if s == "" {
			continue
		}
		if i := strings.Index(s, ":"); i >= 0 {
			s = s[i+1:]
		}
		if isInTestdata(s) {
			continue
		}
		paths = append(paths, s)
	}
	return paths
}

// isInTestdata reports whether the slash-separated path has a "testdata"
// segment. Matches Go's own `go build` / `go test` convention of skipping
// `testdata/` subtrees.
func isInTestdata(slashPath string) bool {
	for _, seg := range strings.Split(slashPath, "/") {
		if seg == "testdata" {
			return true
		}
	}
	return false
}
